from __future__ import annotations

__all__ = (
    "AsyncCacheInfo",
    "AsyncCacheParameters",
    "AsyncLRUCacheWrapper",
    "cache",
    "lru_cache",
    "reduce",
)

import asyncio
import functools
import sys
from collections import OrderedDict
from typing import (
    Any,
    Awaitable,
    Callable,
    Hashable,
    NamedTuple,
    TypedDict,
    TypeVar,
    overload,
)

try:
    from typing import ParamSpec
except Exception:
    from typing_extensions import ParamSpec

from functools import update_wrapper, reduce as _reduce

# Optional cooperative cancellation checkpoint, fall back to noop if unavailable.
try:
    from .lowlevel import checkpoint
except Exception:
    async def checkpoint():
        return None  # type: ignore

T = TypeVar("T")
P = ParamSpec("P")


class AsyncCacheInfo(NamedTuple):
    hits: int
    misses: int
    maxsize: int | None
    currsize: int


class AsyncCacheParameters(TypedDict):
    maxsize: int | None
    typed: bool
    always_checkpoint: bool


class _InFlight:
    """Marker object holding an asyncio.Future for in-flight calls."""
    __slots__ = ("future",)

    def __init__(self, fut: asyncio.Future):
        self.future = fut


class _BoundMethodWrapper:
    def __init__(self, wrapper: "AsyncLRUCacheWrapper", instance: object):
        self.__wrapper = wrapper
        self.__instance = instance

    def cache_info(self) -> AsyncCacheInfo:
        return self.__wrapper.cache_info()

    def cache_parameters(self) -> AsyncCacheParameters:
        return self.__wrapper.cache_parameters()

    def cache_clear(self) -> None:
        self.__wrapper.cache_clear()

    async def __call__(self, *args: Any, **kwargs: Any) -> Any:
        if self.__instance is None:
            return await self.__wrapper(*args, **kwargs)
        return await self.__wrapper(self.__instance, *args, **kwargs)


class AsyncLRUCacheWrapper:
    """Async LRU cache wrapper for coroutine functions."""

    def __init__(
        self,
        func: Callable[P, Awaitable[T]],
        maxsize: int | None = 128,
        typed: bool = False,
        always_checkpoint: bool = False,
    ):
        if not asyncio.iscoroutinefunction(func):
            raise TypeError("AsyncLRUCacheWrapper requires an async function")

        self.__wrapped__ = func
        update_wrapper(self, func)

        self._maxsize = maxsize if maxsize is None or maxsize >= 0 else 0
        self._typed = bool(typed)
        self._always_checkpoint = bool(always_checkpoint)

        self._cache: "OrderedDict[Hashable, tuple[T, None] | tuple[_InFlight, None]]" = OrderedDict()
        self._hits = 0
        self._misses = 0
        # protect structural mutations of the cache
        self._lock = asyncio.Lock()

    def cache_info(self) -> AsyncCacheInfo:
        return AsyncCacheInfo(self._hits, self._misses, self._maxsize, len(self._cache))

    def cache_parameters(self) -> AsyncCacheParameters:
        return {
            "maxsize": self._maxsize,
            "typed": self._typed,
            "always_checkpoint": self._always_checkpoint,
        }

    def cache_clear(self) -> None:
        """Clear the cache and reset statistics."""
        # Synchronous clear - ensure no concurrent mutations
        async def _clear():
            async with self._lock:
                # Cancel any in-flight futures to avoid leaks
                for val in self._cache.values():
                    if isinstance(val[0], _InFlight):
                        fut = val[0].future
                        if not fut.done():
                            fut.cancel()
                self._cache.clear()
                self._hits = 0
                self._misses = 0

        # Schedule synchronous execution of the async clear helper
        try:
            loop = asyncio.get_running_loop()
            # we're in an event loop; run the coroutine
            loop.create_task(_clear())
        except RuntimeError:
            # no running loop; run directly
            asyncio.run(_clear())

    def __get__(self, instance: object, owner: type | None = None):
        return _BoundMethodWrapper(self, instance)

    def _make_key(self, args: tuple, kwargs: dict) -> Hashable:
        if not kwargs:
            base = args
        else:
            # preserve kwargs order by converting to tuple of items
            base = args + ("_kw",) + tuple(kwargs.items())
        if self._typed:
            types = tuple(type(a) for a in args)
            if kwargs:
                types += tuple(type(v) for v in kwargs.values())
            return (base, types)
        return base

    async def __call__(self, *args: Any, **kwargs: Any) -> Any:
        """Call the wrapped function, using the cache when possible."""
        try:
            key = self._make_key(args, kwargs)
            hash(key)  # ensure key is hashable
        except Exception:
            # Can't cache unhashable arguments; call directly
            if self._always_checkpoint:
                await checkpoint()
            return await self.__wrapped__(*args, **kwargs)

        async with self._lock:
            entry = self._cache.get(key)
            if entry is not None:
                value = entry[0]
                # If in-flight, wait on its future outside the global lock
                if isinstance(value, _InFlight):
                    fut = value.future
                    # Move to end to mark as recently used
                    self._cache.move_to_end(key)
                    # release lock before awaiting
                    wait_future = fut
                    # increment hits only after successful await below
                    pass_out = True
                else:
                    # cached result
                    self._hits += 1
                    self._cache.move_to_end(key)
                    return value  # type: ignore
            else:
                # cache miss: create a future placeholder and insert it
                loop = asyncio.get_running_loop()
                fut: asyncio.Future = loop.create_future()
                inflight = _InFlight(fut)
                self._cache[key] = (inflight, None)
                self._misses += 1
                # enforce maxsize
                if self._maxsize is not None and len(self._cache) > self._maxsize:
                    # pop oldest
                    old_key, old_val = self._cache.popitem(last=False)
                    # cancel in-flight if any to avoid dangling futures
                    if isinstance(old_val[0], _InFlight):
                        old_fut = old_val[0].future
                        if not old_fut.done():
                            old_fut.cancel()
                # we'll compute the result; release lock and continue below
                wait_future = None
                pass_out = False

        # If we reached here with wait_future set, that means another coroutine is computing the result
        if wait_future is not None:
            try:
                result = await wait_future
                # consider this a hit
                self._hits += 1
                return result
            except asyncio.CancelledError:
                # Propagate cancellation
                raise
            except Exception:
                # If the in-flight computation failed, re-raise its exception
                raise

        # We are responsible for computing the result and completing the future
        try:
            if self._always_checkpoint:
                await checkpoint()
            result = await self.__wrapped__(*args, **kwargs)
        except Exception as exc:
            # Set exception on future and remove cache entry
            async with self._lock:
                # Try to retrieve the placeholder; if still present and in-flight, set exception
                entry = self._cache.get(key)
                if entry and isinstance(entry[0], _InFlight):
                    fut = entry[0].future
                    if not fut.done():
                        fut.set_exception(exc)
                    # remove the failed entry
                    try:
                        del self._cache[key]
                    except KeyError:
                        pass
            raise
        else:
            # Store the result and resolve future
            async with self._lock:
                entry = self._cache.get(key)
                if entry and isinstance(entry[0], _InFlight):
                    fut = entry[0].future
                    if not fut.done():
                        fut.set_result(result)
                    # replace in-flight with concrete result
                    self._cache[key] = (result, None)
                    # enforce maxsize again (in case size changed)
                    if self._maxsize is not None and len(self._cache) > self._maxsize:
                        old_key, old_val = self._cache.popitem(last=False)
                        if isinstance(old_val[0], _InFlight):
                            old_fut = old_val[0].future
                            if not old_fut.done():
                                old_fut.cancel()
                else:
                    # placeholder disappeared (unlikely); insert result
                    self._cache[key] = (result, None)
                    if self._maxsize is not None and len(self._cache) > self._maxsize:
                        old_key, old_val = self._cache.popitem(last=False)
                        if isinstance(old_val[0], _InFlight):
                            old_fut = old_val[0].future
                            if not old_fut.done():
                                old_fut.cancel()
            return result


def lru_cache(maxsize: int | None = 128, typed: bool = False, always_checkpoint: bool = False):
    """Decorator factory returning an AsyncLRUCacheWrapper for async functions."""
    def decorating_function(user_function: Callable[P, Awaitable[T]]):
        return AsyncLRUCacheWrapper(user_function, maxsize=maxsize, typed=typed, always_checkpoint=always_checkpoint)
    return decorating_function


# Alias for familiarity
cache = lru_cache

# Export standard reduce
reduce = _reduce